import React, { useState, useEffect, useCallback, useRef } from 'react';
import { productsAPI } from '../../api';
import ProductCard from '../../components/ProductCard/ProductCard';
import AdModal from '../../components/AdModal/AdModal';
import { useCart } from '../../context/CartContext';
import styles from './CatalogPage.module.css';

const CATEGORIES = [
  { value: '', label: 'Все' },
  { value: 'vegetables', label: '🥕 Овощи' },
  { value: 'fruits',     label: '🍎 Фрукты' },
  { value: 'desserts',   label: '🍰 Десерты' },
];

export default function CatalogPage() {
  const [products, setProducts]   = useState([]);
  const [total, setTotal]         = useState(0);
  const [loading, setLoading]     = useState(true);
  const [category, setCategory]   = useState('');
  const [search, setSearch]       = useState('');
  const [minPrice, setMinPrice]   = useState('');
  const [maxPrice, setMaxPrice]   = useState('');
  const [page, setPage]           = useState(1);
  const [adCategory, setAdCategory] = useState(null);

  const { items } = useCart();
  const prevCount = useRef(items.length);

  // Показываем попап при добавлении товара
  useEffect(() => {
    if (items.length > prevCount.current) {
      const newItem = items[items.length - 1];
      setAdCategory(newItem.category);
    }
    prevCount.current = items.length;
  }, [items]);

  const fetchProducts = useCallback(async () => {
    setLoading(true);
    try {
      const params = { page, limit: 12 };
      if (category)  params.category  = category;
      if (search)    params.search    = search;
      if (minPrice)  params.min_price = parseFloat(minPrice);
      if (maxPrice)  params.max_price = parseFloat(maxPrice);

      const { data } = await productsAPI.getAll(params);
      setProducts(data.products || []);
      setTotal(data.total || 0);
    } catch {
      setProducts([]);
    } finally {
      setLoading(false);
    }
  }, [category, search, minPrice, maxPrice, page]);

  // Дебаунс для поиска
  useEffect(() => {
    const timer = setTimeout(fetchProducts, 400);
    return () => clearTimeout(timer);
  }, [fetchProducts]);

  const totalPages = Math.ceil(total / 12);

  return (
    <div className={styles.page}>
      <div className="container">
        <div className={styles.header}>
          <h1 className="section-title">Каталог</h1>
          <p className="section-subtitle">
            Найдено товаров: <strong>{total}</strong>
          </p>
        </div>

        {/* Фильтры */}
        <div className={styles.filters}>
          {/* Поиск */}
          <div className={styles.searchWrap}>
            <span className={styles.searchIcon}>🔍</span>
            <input
              type="text"
              className={styles.searchInput}
              placeholder="Поиск товаров..."
              value={search}
              onChange={(e) => { setSearch(e.target.value); setPage(1); }}
            />
          </div>

          {/* Категории */}
          <div className={styles.categoryTabs}>
            {CATEGORIES.map((cat) => (
              <button
                key={cat.value}
                className={`${styles.categoryTab} ${category === cat.value ? styles.active : ''}`}
                onClick={() => { setCategory(cat.value); setPage(1); }}
              >
                {cat.label}
              </button>
            ))}
          </div>

          {/* Диапазон цен */}
          <div className={styles.priceRange}>
            <input
              type="number"
              className={styles.priceInput}
              placeholder="От ₽"
              value={minPrice}
              onChange={(e) => { setMinPrice(e.target.value); setPage(1); }}
              min="0"
            />
            <span className={styles.priceSep}>—</span>
            <input
              type="number"
              className={styles.priceInput}
              placeholder="До ₽"
              value={maxPrice}
              onChange={(e) => { setMaxPrice(e.target.value); setPage(1); }}
              min="0"
            />
          </div>
        </div>

        {/* Сетка товаров */}
        {loading ? (
          <div className={styles.grid}>
            {Array.from({ length: 12 }).map((_, i) => (
              <div key={i} className={`${styles.skeletonCard} skeleton`} />
            ))}
          </div>
        ) : products.length === 0 ? (
          <div className={styles.empty}>
            <span className={styles.emptyIcon}>🔍</span>
            <p>Товары не найдены</p>
            <p className={styles.emptyHint}>Попробуйте изменить фильтры</p>
          </div>
        ) : (
          <div className={styles.grid}>
            {products.map((p) => (
              <ProductCard
                key={p.id}
                product={p}
                featured={p.is_day_item}
              />
            ))}
          </div>
        )}

        {/* Пагинация */}
        {totalPages > 1 && (
          <div className={styles.pagination}>
            <button
              className={`btn btn-outline btn-sm ${styles.pageBtn}`}
              onClick={() => setPage((p) => Math.max(1, p - 1))}
              disabled={page === 1}
            >
              ← Назад
            </button>
            <span className={styles.pageInfo}>
              {page} / {totalPages}
            </span>
            <button
              className={`btn btn-outline btn-sm ${styles.pageBtn}`}
              onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
              disabled={page === totalPages}
            >
              Вперёд →
            </button>
          </div>
        )}
      </div>

      {/* Рекламный попап */}
      {adCategory && (
        <AdModal
          triggerCategory={adCategory}
          onClose={() => setAdCategory(null)}
        />
      )}
    </div>
  );
}
